codeExample:
# *args
def add_all(*numbers):
    return sum(numbers)

print(add_all(1, 2, 3, 4, 5))

# **kwargs
def show_info(**data):
    for key, value in data.items():
        print(f"  {key}: {value}")

show_info(name="Alice", age=25)

# Unpacking
nums = [1, 2, 3]
def add(a, b, c):
    return a + b + c
print(add(*nums))

params = {"a": 1, "b": 2, "c": 3}
print(add(**params))
